     1→import { Inject, Injectable, Logger } from '@nestjs/common';
     2→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
     3→import { Db } from '@shared/database/types';
     4→import { NetworksService } from '@modules/networks/services/networks.service';
     5→import { HdWalletService } from '@modules/networks/services/hd-wallet.service';
     6→import { CurrencyService } from '@modules/currency/services/currency.service';
     7→import { networksConfigs } from '@configs/networks.configs';
     8→import { ConfigType } from '@nestjs/config';
     9→import { SupportedNetworks } from '@modules/networks/types/network.type';
    10→import { Selectable } from 'kysely';
    11→import { DepositPoolAccountEntity } from '@entities/balance.entity';
    12→import { CurrencyEntity } from '@entities/currency.entity';
    13→import Decimal from 'decimal.js';
    14→
    15→@Injectable()
    16→export class DepositPoolMonitoringService {
    17→  constructor(
    18→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    19→    private readonly networksService: NetworksService,
    20→    private readonly hdWalletService: HdWalletService,
    21→    private readonly currencyService: CurrencyService,
    22→    @Inject(networksConfigs.KEY)
    23→    private readonly networksConfig: ConfigType<typeof networksConfigs>,
    24→  ) {
    25→    //this.monitorPoolAccounts(SupportedNetworks.TRON);
    26→  }
    27→  private readonly logger = new Logger(DepositPoolMonitoringService.name);
    28→
    29→  /**
    30→   * Monitors pool accounts and sweeps funds if balance exceeds threshold
    31→   * Sweeps funds keeping min_deposit_pool_account_amount in the pool account
    32→   */
    33→  async monitorPoolAccounts(network: SupportedNetworks): Promise<void> {
    34→    const trx = await this.db.startTransaction().execute();
    35→    try {
    36→      // Get all pool accounts for
    37→      const poolAccounts = await trx
    38→        .selectFrom('depositPoolAccount')
    39→        // for update to prevent concurrent access
    40→        .forUpdate()
    41→        .selectAll()
    42→        .where('network', '=', network)
    43→        .where((eb) =>
    44→          eb.or([
    45→            eb('lastMonitorAt', 'is', null),
    46→            eb('lastMonitorAt', '<', new Date(Date.now() - 15 * 60 * 1000)), // Only check accounts that have not been monitored yet or lastMonitorAt was more then 15 minutes ago
    47→          ]),
    48→        )
    49→        .where((eb) =>
    50→          eb(
    51→            'id',
    52→            'not in',
    53→            eb
    54→              .selectFrom('depositPoolAccountLocks')
    55→              .select('depositPoolAccountId'),
    56→          ),
    57→        )
    58→        .execute();
    59→
    60→      if (poolAccounts.length === 0) {
    61→        this.logger.log({ message: 'No pool accounts to monitor', network });
    62→        await trx.rollback().execute();
    63→        return;
    64→      }
    65→
    66→      this.logger.log({
    67→        message: `Found ${poolAccounts.length} pool accounts to monitor in ${network} network`,
    68→        network,
    69→      });
    70→
    71→      const outstandingAccount =
    72→        await this.networksService.getOutstandingAccountByNetwork(network);
    73→
    74→      if (!outstandingAccount) {
    75→        this.logger.warn({ message: 'Outstanding account not found', network });
    76→        await trx.rollback().execute();
    77→        return;
    78→      }
    79→
    80→      const networkCurrencies = await this.currencyService.getCurrencies({
    81→        network,
    82→      });
    83→
    84→      // Find base currency that matches the network
    85→      const baseCurrency = networkCurrencies.find(
    86→        (c) => !c.contractAddress && c.network === network,
    87→      );
    88→
    89→      // Process each pool account
    90→      for (const poolAccount of poolAccounts) {
    91→        // Get currency information (lockedCurrencyId is guaranteed to be set since we filtered for it)
    92→
    93→        if (!baseCurrency) {
    94→          this.logger.warn({ message: 'Base currency not found', network });
    95→          continue;
    96→        }
    97→
    98→        await this.sweepBalanceIfRequired(
    99→          poolAccount,
   100→          networkCurrencies,
   101→          outstandingAccount,
   102→        ).catch((error) => {
   103→          this.logger.error({
   104→            error,
   105→            message: 'Failed to sweep balance if required',
   106→            poolAccountId: poolAccount.id,
   107→            network,
   108→          });
   109→        });
   110→        await this.topUpIfNeeded(
   111→          poolAccount,
   112→          baseCurrency,
   113→          outstandingAccount,
   114→        ).catch((error) => {
   115→          this.logger.error({
   116→            error,
   117→            message: 'Failed to top up if needed',
   118→            poolAccountId: poolAccount.id,
   119→            network,
   120→          });
   121→        });
   122→
   123→        await trx
   124→          .updateTable('depositPoolAccount')
   125→          .set({
   126→            lastMonitorAt: new Date(),
   127→          })
   128→          .where('id', '=', poolAccount.id)
   129→          .execute();
   130→      }
   131→
   132→      await trx.commit().execute();
   133→    } catch (error) {
   134→      await trx.rollback().execute();
   135→      this.logger.error({
   136→        error,
   137→        message: 'Failed to monitor and sweep pool accounts',
   138→        network,
   139→      });
   140→      throw error;
   141→    }
   142→  }
   143→
   144→  private async sweepBalanceIfRequired(
   145→    poolAccount: Selectable<DepositPoolAccountEntity>,
   146→    networkCurrencies: Selectable<CurrencyEntity>[],
   147→    outstandingAccount: { address: string; privateKey: string },
   148→  ): Promise<void> {
   149→    for (const currency of networkCurrencies) {
   150→      const balance = await this.networksService.getBalanceByAddress(
   151→        poolAccount.network,
   152→        poolAccount.address,
   153→        currency.contractAddress,
   154→      );
   155→      if (
   156→        balance.found &&
   157→        new Decimal(balance.amount).gt(
   158→          currency.thresholdPoolAccountBalanceToSweep,
   159→        )
   160→      ) {
   161→        const optimalAmount = new Decimal(currency.optimalPoolAccountBalance);
   162→        const sweepAmount = optimalAmount.minus(balance.amount).abs();
   163→
   164→        const date = new Date();
   165→        const idempotencyKey = `monitoring-sweep-${poolAccount.id}-${currency.code}-${date.getUTCFullYear()}-${date.getUTCMonth()}-${date.getUTCDate()}-${date.getUTCHours()}-${date.getUTCMinutes()}}`;
   166→
   167→        const { privateKey } = this.hdWalletService.deriveAndVerify(
   168→          poolAccount.network,
   169→          poolAccount.derivationIndex,
   170→          poolAccount.address,
   171→        );
   172→
   173→        await this.networksService.sweepFunds(
   174→          poolAccount.network,
   175→          currency.code,
   176→          {
   177→            fromPrivateKey: privateKey,
   178→            fromAddress: poolAccount.address,
   179→            toAddress: outstandingAccount.address,
   180→            amount: sweepAmount.toString(),
   181→            idempotencyKey,
   182→          },
   183→        );
   184→      }
   185→    }
   186→  }
   187→
   188→  // Use only for base currency
   189→  async topUpIfNeeded(
   190→    poolAccount: Selectable<DepositPoolAccountEntity>,
   191→    currency: Selectable<CurrencyEntity>,
   192→    outstandingAccount: { address: string; privateKey: string },
   193→  ): Promise<void> {
   194→    const balance = await this.networksService.getBalanceByAddress(
   195→      poolAccount.network,
   196→      poolAccount.address,
   197→      null,
   198→    );
   199→    const balanceDecimal = new Decimal(balance.amount);
   200→    if (balanceDecimal.lt(currency.minPoolAccountBalance)) {
   201→      // min = 50, optimal = 250, threshold = 500
   202→      // topup amount = optimal - 40 - min
   203→      const topupAmount = new Decimal(currency.optimalPoolAccountBalance).minus(
   204→        balanceDecimal,
   205→      );
   206→      //console.log('topupAmount', topupAmount.toString());
   207→      const date = new Date();
   208→      const idempotencyKey = `monitoring-topup-${poolAccount.id}-${currency.code}-${date.getUTCFullYear()}-${date.getUTCMonth()}-${date.getUTCDate()}-${date.getUTCHours()}-${date.getUTCMinutes()}}`;
   209→      this.logger.debug({
   210→        message: 'Topping up pool account',
   211→        poolAccountId: poolAccount.id,
   212→        topupAmount,
   213→        currency: currency.code,
   214→      });
   215→      await this.networksService.sweepFunds(
   216→        poolAccount.network,
   217→        currency.code,
   218→        {
   219→          fromAddress: outstandingAccount.address,
   220→          fromPrivateKey: outstandingAccount.privateKey,
   221→          toAddress: poolAccount.address,
   222→          amount: topupAmount.toString(),
   223→          idempotencyKey,
   224→        },
   225→      );
   226→    }
   227→  }
   228→}
