     5→import { INetworkAccount } from '../types/network-account.type';
     6→import { SupportedNetworks } from '../types/network.type';
     7→import { HttpStatus, Inject, Injectable, Logger } from '@nestjs/common';
     8→import { ExceptionFactory } from '@shared/exceptions';
     9→import { CurrencyService } from '@modules/currency/services/currency.service';
    10→import { IGetTransactionHistoryParams } from '../types/network.type';
    11→import { INetworkTransaction } from '../types/network.type';
    12→import { ISweepBaseParams } from '../types/network-service';
    13→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
    14→import { Db } from '@shared/database/types';
    15→import { NotificationsService } from '@modules/notifications/services/notifications.service';
    16→import { DEFAULT_REDIS_TOKEN } from '@configs/redis.config';
    17→import { Redis } from 'ioredis';
    18→import { SweepRecordEntity } from '@entities/balance.entity';
    19→import { CurrencyEntity } from '@entities/currency.entity';
    20→import { UUID } from 'crypto';
    21→import { Selectable } from 'kysely';
    22→import { networksConfigs } from '@configs/networks.configs';
    23→import { ConfigType } from '@nestjs/config';
    24→
    25→const STALE_SWEEP_THRESHOLD_MS = 5 * 60 * 1000;
    26→const SWEEP_LOCK_TTL_SECONDS = 300;
    27→const SWEEP_LOCK_RETRY_DELAY_MS = 2000;
    28→
    29→@Injectable()
    30→export class NetworksService {
    31→  constructor(
    32→    private readonly tronNetworkService: TronNetworkService,
    33→    private readonly ethereumNetworkService: EthereumNetworkService,
    34→    private readonly bnbNetworkService: BnbNetworkService,
    35→    private readonly btcNetworkService: BtcNetworkService,
    36→    private readonly currencyService: CurrencyService,
    37→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    38→    private readonly notificationsService: NotificationsService,
    39→    @Inject(DEFAULT_REDIS_TOKEN)
    40→    private readonly redis: Redis,
    41→    @Inject(networksConfigs.KEY)
    42→    private readonly networksConfig: ConfigType<typeof networksConfigs>,
    43→  ) {}
    44→
    45→  private readonly logger = new Logger(NetworksService.name);
    46→
    47→  async createAccount(network: SupportedNetworks): Promise<INetworkAccount> {
    48→    switch (network) {
    49→      case SupportedNetworks.TRON:
    50→        return this.tronNetworkService.createAccount();
    51→      case SupportedNetworks.ETHEREUM:
    52→        return this.ethereumNetworkService.createAccount();
    53→      case SupportedNetworks.BNB:
    54→        return this.bnbNetworkService.createAccount();
    55→      case SupportedNetworks.BTC:
    56→        return this.btcNetworkService.createAccount();
    57→      case SupportedNetworks.SOLANA:
    58→        throw ExceptionFactory.create({
    59→          exceptionCode: 'network.solanaNotSupported',
    60→          statusCode: HttpStatus.BAD_REQUEST,
    61→          message: 'Solana network is not supported yet',
    62→        });
    63→      default:
    64→        throw ExceptionFactory.create({
    65→          exceptionCode: 'network.unsupportedNetwork',
    66→          statusCode: HttpStatus.BAD_REQUEST,
    67→          message: 'Unsupported network',
    68→        });
    69→    }
    70→  }
    71→
    72→  /**
    73→   * Gets the current balance of a currency at the specified address
    74→   * @param network The network to check
    75→   * @param address The address to check
    76→   * @param contractAddress The token contract address (null for native currency)
    77→   * @returns Current balance as a string
    78→   */
    79→  async getBalanceByAddress(
    80→    network: SupportedNetworks,
    81→    address: string,
    82→    contractAddress: string | null,
    83→  ): Promise<{ found: boolean; amount: string }> {
    84→    try {
    85→      let balance: string;
    86→
    87→      if (contractAddress === null) {
    88→        // Base currency (TRX, ETH, etc.)
    89→        switch (network) {
    90→          case SupportedNetworks.TRON:
    91→            balance = await this.tronNetworkService.getTrxBalance(address);
    92→            break;
    93→          case SupportedNetworks.ETHEREUM:
    94→            balance = await this.ethereumNetworkService.getBalance(address);
    95→            break;
    96→          case SupportedNetworks.BNB:
    97→            balance = await this.bnbNetworkService.getBalance(address);
    98→            break;
    99→          case SupportedNetworks.BTC:
   100→            balance = await this.btcNetworkService.getBalance(address);
   101→            break;
   102→          case SupportedNetworks.SOLANA:
   103→            throw ExceptionFactory.create({
   104→              exceptionCode: 'network.solanaNotSupported',
   105→              statusCode: HttpStatus.BAD_REQUEST,
   106→              message: 'Solana network is not supported yet',
   107→            });
   108→          default:
   109→            throw ExceptionFactory.create({
   110→              exceptionCode: 'network.unsupportedNetwork',
   111→              statusCode: HttpStatus.BAD_REQUEST,
   112→              message: 'Unsupported network',
   113→            });
   114→        }
   115→      } else {
   116→        // Token currency - find currency by contract address
   117→        const currencies = await this.currencyService.getCurrencies({});
   118→        const tokenCurrency = currencies.find(
   119→          (c) => c.contractAddress === contractAddress && c.network === network,
   120→        );
   121→
   122→        if (!tokenCurrency) {
   123→          throw ExceptionFactory.create({
   124→            exceptionCode: 'network.currencyNotFoundByContract',
   125→            statusCode: HttpStatus.BAD_REQUEST,
   126→            message: `Currency not found for contract address: ${contractAddress}`,
   127→          });
   128→        }
   129→
   130→        switch (network) {
   131→          case SupportedNetworks.TRON:
   132→            balance = await this.tronNetworkService.getTokenBalance(
   133→              address,
   134→              tokenCurrency.code,
   135→            );
   136→            break;
   137→          case SupportedNetworks.ETHEREUM:
   138→            balance = await this.ethereumNetworkService.getTokenBalance(
   139→              address,
   140→              contractAddress,
   141→              tokenCurrency.decimalPlaces,
   142→            );
   143→            break;
   144→          case SupportedNetworks.BNB:
   145→            balance = await this.bnbNetworkService.getTokenBalance(
   146→              address,
   147→              contractAddress,
   148→              tokenCurrency.decimalPlaces,
   149→            );
   150→            break;
   151→          case SupportedNetworks.BTC:
   152→            throw ExceptionFactory.create({
   153→              exceptionCode: 'network.btcTokensNotSupported',
   154→              statusCode: HttpStatus.BAD_REQUEST,
   155→              message: 'Bitcoin does not support token transfers',
   156→            });
   157→          case SupportedNetworks.SOLANA:
   158→            throw ExceptionFactory.create({
   159→              exceptionCode: 'network.solanaNotSupported',
   160→              statusCode: HttpStatus.BAD_REQUEST,
   161→              message: 'Solana network is not supported yet',
   162→            });
   163→          default:
   164→            throw ExceptionFactory.create({
   165→              exceptionCode: 'network.unsupportedNetwork',
   166→              statusCode: HttpStatus.BAD_REQUEST,
   167→              message: 'Unsupported network',
   168→            });
   169→        }
   170→      }
   171→
   172→      const amount = parseFloat(balance);
   173→      return {
   174→        found: amount > 0,
   175→        amount: balance,
   176→      };
   177→    } catch (error) {
   178→      this.logger.error({ error, message: 'Failed to get balance by address' });
   179→      return { found: false, amount: '0' };
   180→    }
   181→  }
   182→
   183→  /**
   184→   * Sweeps funds from a wallet to a destination address.
   185→   * Multi-layer idempotency: DB (source of truth) → Redis TTL lock → UNIQUE constraint.
   186→   * Safe to retry — returns cached result for completed sweeps, recovers stale pending records.
   187→   */
   188→  async sweepFunds(
   189→    network: SupportedNetworks,
   190→    currencyCode: string,
   191→    options: Required<ISweepBaseParams>,
   192→  ): Promise<{ swept: boolean; transactionHash?: string; amount?: string }> {
   193→    // Layer 1: Check DB first (source of truth)
   194→    const existingRecord = await this.db
   195→      .selectFrom('sweepRecord')
   196→      .selectAll()
   197→      .where('idempotencyKey', '=', options.idempotencyKey)
   198→      .executeTakeFirst();
   199→
   200→    if (existingRecord) {
   201→      return this.handleExistingSweepRecord(existingRecord, network);
   202→    }
   203→
   204→    // Layer 2: Acquire distributed lock with TTL
   205→    const lockKey = `sweep-lock:${options.idempotencyKey}`;
   206→    const locked = await this.redis.set(
   207→      lockKey,
   208→      '1',
   209→      'EX',
   210→      SWEEP_LOCK_TTL_SECONDS,
   211→      'NX',
   212→    );
   213→
   214→    if (!locked) {
   215→      await this.delay(SWEEP_LOCK_RETRY_DELAY_MS);
   216→      const recordAfterWait = await this.db
   217→        .selectFrom('sweepRecord')
   218→        .selectAll()
   219→        .where('idempotencyKey', '=', options.idempotencyKey)
   220→        .executeTakeFirst();
   221→      if (recordAfterWait) {
   222→        return this.handleExistingSweepRecord(recordAfterWait, network);
   223→      }
   224→      throw ExceptionFactory.create({
   225→        exceptionCode: 'network.concurrentSweep',
   226→        statusCode: HttpStatus.BAD_REQUEST,
   227→        message: 'Concurrent sweep in progress for this idempotency key',
   228→      });
   229→    }
   230→
   231→    try {
   232→      // Double-check DB after acquiring the lock (another worker may have completed between Layer 1 and lock)
   233→      const doubleCheck = await this.db
   234→        .selectFrom('sweepRecord')
   235→        .selectAll()
   236→        .where('idempotencyKey', '=', options.idempotencyKey)
   237→        .executeTakeFirst();
   238→
   239→      if (doubleCheck) {
   240→        return this.handleExistingSweepRecord(doubleCheck, network);
   241→      }
   242→
   243→      const currency =
   244→        await this.currencyService.getCurrencyByCode(currencyCode);
   245→      if (!currency) {
   246→        throw ExceptionFactory.create({
   247→          exceptionCode: 'network.currencyNotFoundOnNetwork',
   248→          statusCode: HttpStatus.BAD_REQUEST,
   249→          message: `Currency ${currencyCode} not found on ${network}`,
   250→        });
   251→      }
   252→
   253→      this.logger.debug({
   254→        message: 'Initiating sweep',
   255→        currencyCode,
   256→        network,
   257→        fromAddress: options.fromAddress,
   258→        toAddress: options.toAddress,
   259→        amount: options.amount,
   260→      });
   261→
   262→      // Layer 3: INSERT with UNIQUE constraint as final defense
   263→      let sweepRecordId: UUID;
   264→      try {
   265→        const sweepRecord = await this.db
   266→          .insertInto('sweepRecord')
   267→          .returning(['id'])
   268→          .values({
   269→            currencyCode: currency.code,
   270→            fromAddress: options.fromAddress,
   271→            toAddress: options.toAddress,
   272→            amount: options.amount,
   273→            status: 'pending',
   274→            errorMessage: null,
   275→            idempotencyKey: options.idempotencyKey,
   276→          })
   277→          .executeTakeFirstOrThrow();
   278→        sweepRecordId = sweepRecord.id;
   279→      } catch (insertError: unknown) {
   280→        if (this.isUniqueViolation(insertError)) {
   281→          const raceRecord = await this.db
   282→            .selectFrom('sweepRecord')
   283→            .selectAll()
   284→            .where('idempotencyKey', '=', options.idempotencyKey)
   285→            .executeTakeFirst();
   286→          if (raceRecord) {
   287→            return this.handleExistingSweepRecord(raceRecord, network);
   288→          }
   289→        }
   290→        throw insertError;
   291→      }
   292→
   293→      // Layer 4: Execute blockchain transfer
   294→      try {
   295→        const result = await this.executeTransfer(
   296→          network,
   297→          currencyCode,
   298→          currency,
   299→          options,
   300→        );
   301→
   302→        await this.db
   303→          .updateTable('sweepRecord')
   304→          .set({
   305→            status: 'completed',
   306→            transactionHash: result.transactionHash,
   307→          })
   308→          .where('id', '=', sweepRecordId)
   309→          .execute();
   310→
   311→        return {
   312→          swept: true,
   313→          transactionHash: result.transactionHash,
   314→          amount: result.amount,
   315→        };
   316→      } catch (transferError: unknown) {
   317→        await this.db
   318→          .updateTable('sweepRecord')
   319→          .set({
   320→            status: 'failed',
   321→            errorMessage:
   322→              transferError instanceof Error
   323→                ? transferError.message
   324→                : 'Unknown error',
   325→          })
   326→          .where('id', '=', sweepRecordId)
   327→          .execute();
   328→        throw transferError;
   329→      }
   330→    } finally {
   331→      await this.redis.del(lockKey);
   332→    }
   333→  }
   334→
   335→  private async handleExistingSweepRecord(
   336→    record: Selectable<SweepRecordEntity>,
   337→    network: SupportedNetworks,
   338→  ): Promise<{ swept: boolean; transactionHash?: string; amount?: string }> {
   339→    if (record.status === 'completed') {
   340→      return {
   341→        swept: true,
   342→        transactionHash: record.transactionHash ?? undefined,
   343→        amount: record.amount,
   344→      };
   345→    }
   346→
   347→    if (record.status === 'failed') {
   348→      throw ExceptionFactory.create({
   349→        exceptionCode: 'network.sweepFailed',
   350→        statusCode: HttpStatus.BAD_REQUEST,
   351→        message: `Sweep failed for idempotency key: ${record.idempotencyKey}`,
   352→      });
   353→    }
   354→
   355→    // status === 'pending' — previous attempt may be in-flight or crashed
   356→    const age = Date.now() - new Date(record.createdAt).getTime();
   357→    if (age < STALE_SWEEP_THRESHOLD_MS) {
   358→      throw ExceptionFactory.create({
   359→        exceptionCode: 'network.sweepInProgress',
   360→        statusCode: HttpStatus.BAD_REQUEST,
   361→        message: 'Sweep currently in progress',
   362→      });
   363→    }
   364→
   365→    // Stale pending record — attempt blockchain-level recovery
   366→    this.logger.warn({
   367→      message: 'Stale pending sweep record detected, attempting recovery',
   368→      sweepRecordId: record.id,
   369→      idempotencyKey: record.idempotencyKey,
   370→      ageMs: age,
   371→    });
   372→
   373→    if (record.transactionHash) {
   374→      const confirmed = await this.verifyTransactionOnChain(
   375→        network,
   376→        record.transactionHash,
   377→      );
   378→      if (confirmed) {
   379→        await this.db
   380→          .updateTable('sweepRecord')
   381→          .set({ status: 'completed' })
   382→          .where('id', '=', record.id)
   383→          .where('status', '=', 'pending')
   384→          .execute();
   385→
   386→        this.logger.log({
   387→          message: 'Recovered stale sweep — confirmed on-chain',
   388→          sweepRecordId: record.id,
   389→          transactionHash: record.transactionHash,
   390→        });
   391→
   392→        return {
   393→          swept: true,
   394→          transactionHash: record.transactionHash,
   395→          amount: record.amount,
   396→        };
   397→      }
   398→    }
   399→
   400→    // No tx hash or tx not confirmed — mark as failed so caller can retry
   401→    const casResult = await this.db
   402→      .updateTable('sweepRecord')
   403→      .set({
   404→        status: 'failed',
   405→        errorMessage:
   406→          'Stale pending record — no confirmed on-chain transaction',
   407→      })
   408→      .where('id', '=', record.id)
   409→      .where('status', '=', 'pending')
   410→      .executeTakeFirst();
   411→
   412→    if (BigInt(casResult.numUpdatedRows) === 0n) {
   413→      const refreshed = await this.db
   414→        .selectFrom('sweepRecord')
   415→        .selectAll()
   416→        .where('id', '=', record.id)
   417→        .executeTakeFirst();
   418→      if (refreshed && refreshed.status === 'completed') {
   419→        return {
   420→          swept: true,
   421→          transactionHash: refreshed.transactionHash ?? undefined,
   422→          amount: refreshed.amount,
   423→        };
   424→      }
   425→    }
   426→
   427→    this.notificationsService.sendNotification(
   428→      `Stale sweep record marked as failed: ${record.idempotencyKey}`,
   429→    );
