   431→      exceptionCode: 'network.staleSweepRecovered',
   432→      statusCode: HttpStatus.BAD_REQUEST,
   433→      message:
   434→        'Stale sweep record recovered as failed — safe to retry with new attempt',
   435→    });
   436→  }
