    46→    private readonly networksService: NetworksService,
    47→    private readonly currencyService: CurrencyService,
    48→    private readonly depositPoolService: DepositPoolService,
    49→    private readonly balanceService: BalanceService,
    50→    private readonly tenantAccountService: TenantAccountService,
    51→    private readonly outboxEventsService: OutboxEventsService,
    52→  ) {
    53→    super();
    54→  }
    55→
    56→  async process(job: Job<IMonitorDepositJobPayload>): Promise<void> {
    57→    if (job.name === DepositJobsEnum.MONITOR_DEPOSIT) {
    58→      await this.monitorDeposit(job as Job<IMonitorDepositJobPayload>);
    59→      return;
    60→    }
    61→  }
    62→
    63→  /**
    64→   * Monitors a deposit address for incoming transactions
    65→   * Checks the blockchain for transactions matching the deposit criteria
    66→   */
    67→  private async monitorDeposit(
    68→    job: Job<IMonitorDepositJobPayload>,
    69→  ): Promise<void> {
    70→    const { depositId } = job.data;
    71→    const trx = await this.db.startTransaction().execute();
    72→    this.logger.log({ message: 'Monitoring deposit', depositId });
    73→    try {
    74→      const deposit = await this.depositService.getDepositById(depositId, trx, {
    75→        forUpdate: true,
    76→      });
    77→      const currency = await this.currencyService.getCurrencyByCode(
    78→        job.data.currencyCode,
    79→      );
    80→
    81→      if (await this.shouldStopMonitoring(deposit, trx)) {
    82→        await this.depositPoolService.unlockPoolAccount(
    83→          deposit.depositPoolAccountId,
    84→          currency.code,
    85→          trx,
    86→        );
    87→        await trx.commit().execute();
    88→        await this.removeRepeatableMonitorJob(job.repeatJobKey);
    89→        return;
    90→      }
    91→
    92→      const poolAccount = await this.depositPoolService.getAccountById(
    93→        deposit.depositPoolAccountId,
    94→      );
    95→
    96→      // Get currency to determine contract address
    97→
    98→      if (!currency) {
    99→        this.logger.warn({
   100→          message: 'Currency not found',
   101→          currencyCode: job.data.currencyCode,
   102→          network: job.data.network,
   103→        });
   104→        await trx.rollback().execute();
   105→        return;
   106→      }
   107→
   108→      // Check for incoming transactions after deposit creation time
   109→      const depositCreatedAt = deposit.createdAt.getTime();
   110→      const incomingTransactions = await this.checkIncomingTransactions({
   111→        address: poolAccount.address,
   112→        network: job.data.network,
   113→        contractAddress: currency.contractAddress,
   114→        sinceTimestamp: depositCreatedAt,
   115→        decimalPlaces: currency.decimalPlaces,
   116→      });
   117→
   118→      // Find matching transaction for this deposit
   119→      const matchingTransaction = await this.findMatchingTransaction(
   120→        incomingTransactions,
   121→        deposit.amountExpected,
   122→        currency.decimalPlaces,
   123→        currency.minDepositAmount, // minAmount: use expected amount as minimum when not strict
   124→        deposit.createdAt, // dateFrom: use the deposit creation time as the date from
   125→        deposit.strictAmountExpected, // amountStrict: use the deposit's strict flag
   126→      );
   127→
   128→      if (matchingTransaction) {
   129→        await this.completeDeposit(
   130→          {
   131→            depositId: deposit.id,
   132→            network: job.data.network,
   133→            currencyCode: job.data.currencyCode,
   134→            expectedAmount: job.data.expectedAmount,
   135→            poolAccountId: poolAccount.id,
   136→            tenantAccountId: deposit.tenantAccountId,
   137→            failed: false,
   138→            transaction: matchingTransaction.transaction,
   139→            monitorJobKey: job.repeatJobKey,
   140→          },
   141→          trx,
   142→        );
   143→
   144→        await this.depositPoolService.unlockPoolAccount(
   145→          poolAccount.id,
   146→          currency.code,
   147→          trx,
   148→        );
   149→      }
   150→      await trx.commit().execute();
   151→    } catch (error) {
   152→      await trx.rollback().execute();
   153→      this.logger.error({
   154→        error,
   155→        message: 'Failed to monitor deposit',
   156→        depositId,
   157→      });
   158→      // Don't throw - let the job retry
   159→    }
   160→  }
   161→
   162→  /**
   163→   * Checks if monitoring should stop (deposit not found, already processed, expired, etc.)
   164→   */
   165→  private async shouldStopMonitoring(
   166→    deposit: Selectable<DepositEntity> | undefined,
   167→    trx: ControlledTransaction<Database, []>,
   168→  ): Promise<boolean> {
   169→    if (!deposit) {
   170→      this.logger.warn({
   171→        message: 'Deposit not found',
   172→        depositId: deposit?.id,
   173→      });
   174→      return true;
   175→    }
   176→
   177→    if (deposit.status !== DepositStatus.PENDING) {
   178→      this.logger.log({
   179→        message: 'Deposit already processed',
   180→        depositId: deposit.id,
   181→        status: deposit.status,
   182→      });
   183→      return true;
   184→    }
   185→
   186→    if (new Date(deposit.paymentLinkExpiresAt) < new Date()) {
   187→      this.logger.warn({
   188→        message: 'Deposit link expired',
   189→        depositId: deposit.id,
   190→      });
   191→      await this.depositService.promoteDeposit(
   192→        deposit.id,
   193→        { status: DepositStatus.EXPIRED },
   194→        trx,
   195→      );
   196→      return true;
   197→    }
   198→
   199→    return false;
   200→  }
   201→
   202→  /**
   203→   * Removes the repeatable MONITOR_DEPOSIT job once we no longer need to monitor.
   204→   */
   205→  async removeRepeatableMonitorJob(repeatJobKey: string): Promise<void> {
   206→    try {
   207→      await this.depositQueue.removeJobScheduler(repeatJobKey);
   208→      this.logger.debug({
   209→        message: 'Removed repeatable monitor job',
   210→        repeatJobKey,
   211→      });
   212→    } catch (error) {
   213→      this.logger.error({
   214→        error,
   215→        message: 'Failed to remove repeatable monitor job',
   216→        repeatJobKey,
   217→      });
   218→    }
   219→  }
   220→
   221→  /**
   222→   * Checks for incoming transactions to the deposit address after the deposit creation time
   223→   * @param params Parameters object containing address, network, contractAddress, sinceTimestamp, decimalPlaces, minAmount, and optional amountStrict
   224→   * @returns Array of incoming transactions with amounts in human-readable format
   225→   */
   226→  private async checkIncomingTransactions(
   227→    params: ICheckIncomingTransactionsParams,
   228→  ): Promise<Array<INetworkTransaction>> {
   229→    const { address, network, contractAddress, sinceTimestamp, decimalPlaces } =
   230→      params;
   231→    try {
   232→      const transactions = await this.networksService.getTransactionHistory({
   233→        network: network as SupportedNetworks,
   234→        address,
   235→        contractAddress: contractAddress ? contractAddress : null,
   236→        sinceTimestamp,
   237→        onlyTo: true,
   238→        limit: 10,
   239→        onlyConfirmed: true,
   240→        decimalPlaces,
   241→      });
   242→
   243→      // Convert amounts from smallest unit to human-readable format
   244→      // TronGrid returns amounts in smallest units (SUN for TRX, smallest unit for TRC20)
   245→      // Network services return raw amounts, we need to convert them here
   246→      return transactions;
   247→    } catch (error) {
   248→      this.logger.error({
   249→        error,
   250→        message: 'Failed to check incoming transactions',
   251→        address,
   252→        network,
   253→        contractAddress,
   254→      });
   255→      return [];
   256→    }
   257→  }
   258→
   259→  /**
   260→   * Finds a transaction matching the deposit amount (within tolerance)
   261→   * @param transactions Array of incoming transactions
   262→   * @param expectedAmount Expected deposit amount
   263→   * @param decimalPlaces Decimal places for amount comparison
   264→   * @returns Matching transaction or null
   265→   */
   266→  private async findMatchingTransaction(
   267→    transactions: Array<INetworkTransaction>,
   268→    expectedAmount: number,
   269→    _decimalPlaces: number,
   270→    minAmount: number,
   271→    dateFrom: Date,
   272→    amountStrict?: boolean,
   273→  ): Promise<{
   274→    transaction: INetworkTransaction;
   275→  } | null> {
   276→    if (transactions.length === 0) {
   277→      return null;
   278→    }
   279→    const sweepRecords = await this.networksService.getSweepRecord(
   280→      dateFrom,
   281→      new Date(),
   282→    );
   283→    const sweepRecordsMap = new Map<string, 1>();
   284→    for (const sweepRecord of sweepRecords) {
   285→      sweepRecordsMap.set(sweepRecord.transactionHash, 1);
   286→    }
   287→    for (const tx of transactions) {
   288→      if (sweepRecordsMap.has(tx.transactionHash)) {
   289→        continue;
   290→      }
   291→      if (amountStrict) {
   292→        const txAmount = parseFloat(tx.amount);
   293→        const tolerance = expectedAmount * 0.001;
   294→        const amountFrom = txAmount - tolerance;
   295→        const amountTo = txAmount + tolerance;
   296→        if (txAmount >= amountFrom && txAmount <= amountTo) {
   297→          return { transaction: tx };
   298→        }
   299→        continue;
   300→      } else {
   301→        const txAmount = parseFloat(tx.amount);
   302→        if (txAmount >= minAmount) {
   303→          return { transaction: tx };
   304→        }
   305→        continue;
   306→      }
   307→    }
   308→
   309→    return null;
   310→  }
   311→
   312→  /**
   313→   * Completes deposit: marks deposit as completed, updates balance, unlocks pool account
   314→   * Main job in flow - runs after sweep funds child job completes
   315→   */
   316→  private async completeDeposit(
   317→    payload: ICompleteDepositParams & { failed: boolean },
   318→    trx: ControlledTransaction<Database, []>,
   319→  ): Promise<void> {
   320→    const {
   321→      depositId,
   322→      tenantAccountId,
   323→      currencyCode,
   324→      poolAccountId,
   325→      network,
   326→      transaction,
   327→      monitorJobKey,
   328→    } = payload;
   329→
   330→    try {
   331→      const deposit = await this.depositService.getDepositById(depositId, trx, {
   332→        forUpdate: true,
   333→      });
   334→
   335→      if (!deposit) {
   336→        this.logger.error({ message: 'Deposit not found', depositId });
   337→        return;
   338→      }
   339→
   340→      const tenantAccount =
   341→        await this.tenantAccountService.getById(tenantAccountId);
   342→
   343→      const currency =
   344→        await this.currencyService.getCurrencyByCode(currencyCode);
   345→
   346→      const existingBalance = await trx
   347→        .selectFrom('balance')
   348→        .selectAll()
   349→        .where('tenantAccountId', '=', tenantAccountId)
   350→        .where('currencyCode', '=', currencyCode)
   351→        .executeTakeFirst();
   352→
   353→      if (!existingBalance) {
   354→        this.logger.error({
   355→          message: 'Balance not found',
   356→          depositId,
   357→          tenantAccountId,
   358→          currencyCode,
   359→        });
   360→        throw new Error('Balance not found');
   361→      }
   362→
   363→      const commissionInstance = new Commission(
   364→        transaction.amount,
   365→        currency.depositCommission,
   366→      );
   367→      const commissionAmount = commissionInstance.only();
   368→      const balanceToIncrease = commissionInstance.with();
   369→
   370→      // Increase balance by expected amount
   371→      await this.balanceService.increaseBalance(
   372→        existingBalance.id,
   373→        balanceToIncrease,
   374→        currency.decimalPlaces,
   375→        trx,
   376→        {
   377→          operation: BalanceOperationType.DEPOSIT,
   378→          relatedEntityId: depositId,
   379→          relatedEntityName: 'DepositEntity',
   380→          operationMeta: {
   381→            transactionHash: transaction.transactionHash,
   382→            actuallyReceivedAmount: transaction.amount,
   383→            commissionAmount,
   384→          },
   385→        },
   386→      );
   387→
   388→      // Update deposit status to completed (sweep transaction hash should already be set by sweep job)
   389→      const actuallyReceivedAmountUSD = await this.currencyService.amountToUSD(
   390→        transaction.amount,
   391→        currency.code,
   392→      );
   393→      await this.depositService.promoteDeposit(
   394→        depositId,
   395→        {
   396→          status: DepositStatus.COMPLETED,
   397→          commissionAmount: parseFloat(commissionAmount),
   398→          depositTransactionHash: transaction.transactionHash,
   399→          actuallyReceivedAmount: parseFloat(transaction.amount),
   400→          actuallyReceivedAmountUSD: parseFloat(actuallyReceivedAmountUSD),
   401→        },
   402→        trx,
   403→      );
   404→
   405→      this.logger.log({
   406→        message: 'Deposit completed',
   407→        depositId,
   408→        amount: transaction.amount,
   409→      });
   410→
   411→      this.outboxEventsService.publish<IDepositCompitedOutboxEventPayload>(
   412→        DEPOSIT_COMPITED_OUTBOX_EVENT_NAME,
   413→        {
   414→          tenantId: tenantAccount.tenantId,
   415→          depositId,
   416→          network: network as SupportedNetworks,
   417→          currencyCode: currency.code,
   418→          amount: transaction.amount,
   419→          commissionAmount: parseFloat(commissionAmount),
   420→          poolAccountId,
   421→          depositTransactionHash: transaction.transactionHash,
   422→          status: deposit.status,
   423→          monitorJobKey,
   424→        },
   425→        3,
   426→        trx,
   427→      );
   428→    } catch (error) {
   429→      this.logger.error({
   430→        error,
   431→        message: 'Failed to complete deposit',
   432→        depositId,
   433→      });
   434→      throw error;
   435→    }
   436→  }
   437→}
