    23→  private readonly logger = new Logger(DepositPoolProcessor.name);
    24→
    25→  async process(job: Job<unknown>): Promise<void> {
    26→    if (job.name === DepositPoolJobsEnum.MONITOR_DEPOSIT_ACCOUNT_POOL) {
    27→      if (!this.depositConf.depositPoolAccountsMonitoringEnabled) {
    28→        this.logger.warn('deposit pool accounts monitoring is disabled');
    29→        return;
    30→      }
    31→      this.logger.verbose('monitoring deposit account pool');
    32→      // Monitor all supported networks
    33→      for (const network of Object.values(SupportedNetworks)) {
    34→        try {
    35→          await this.depositPoolMonitoringService.monitorPoolAccounts(network);
    36→        } catch (error) {
    37→          this.logger.error({
    38→            error,
    39→            message: 'Failed to monitor pool accounts for network',
    40→            network,
    41→          });
    42→          // Continue with other networks even if one fails
    43→        }
    44→      }
    45→    }
    46→  }
    47→
    48→  async scheduleMonitorDepositAccountPool(): Promise<void> {
    49→    await this.depositPoolQueue.upsertJobScheduler(
    50→      DepositPoolJobsEnum.MONITOR_DEPOSIT_ACCOUNT_POOL,
    51→      {
    52→        every: 60_000 * 30, // every 30 minutes,
    53→      },
    54→      {
    55→        opts: {
    56→          repeatJobKey: 'monitor-deposit-account-pool',
    57→        },
    58→      },
    59→    );
    60→
    61→    this.logger.verbose('scheduled monitor deposit account pool');
    62→  }
    63→
    64→  async onModuleInit(): Promise<void> {
    65→    await this.scheduleMonitorDepositAccountPool().catch((error) => {
    66→      this.logger.error(
    67→        'failed to schedule monitor deposit account pool',
    68→        error,
    69→      );
    70→    });
    71→  }
    72→}
