   325→    status: WithdrawalStatus,
   326→    _trx?: ControlledTransaction<Database, []>,
   327→    options?: { transactionHash?: string },
   328→  ): Promise<void> {
   329→    const setClause: Record<string, unknown> = { status };
   330→    if (options?.transactionHash) {
   331→      setClause.transactionHash = options.transactionHash;
   332→    }
   333→
   334→    await (_trx ?? this.db)
