   341→  /**
   342→   * Atomically transitions a withdrawal from `fromStatus` to `toStatus`.
   343→   * Returns true if the row was updated (i.e. the expected status matched).
   344→   */
   345→  async compareAndSetStatus(
   346→    withdrawalId: UUID,
   347→    fromStatus: WithdrawalStatus,
   348→    toStatus: WithdrawalStatus,
   349→    options: {
   350→      transactionHash?: string;
   351→      trx: ControlledTransaction<Database, []>;
   352→    },
   353→  ): Promise<boolean> {
   354→    const setClause: Record<string, unknown> = { status: toStatus };
   355→    if (options?.transactionHash) {
   356→      setClause.transactionHash = options.transactionHash;
   357→    }
   358→
   359→    const result = await options.trx
   360→      .updateTable('withdrawal')
   361→      .set(setClause)
   362→      .where('id', '=', withdrawalId)
   363→      .where('status', '=', fromStatus)
   364→      .executeTakeFirst();
   365→
   366→    return BigInt(result.numUpdatedRows) > 0n;
   367→  }
