   390→  private async handleCrossCurrencyDeduction(
   391→    trx: ControlledTransaction<Database, []>,
   392→    tenantAccountId: UUID,
   393→    primaryBalanceId: UUID,
   394→    totalDeductionInPrimary: Decimal,
   395→    primaryCurrencyCode: string,
   396→    withdrawalId: UUID,
   397→  ): Promise<{
   398→    usedCurrencyCode: string;
   399→    commissionAmount: number;
   400→    commissionAmountUsd: number;
   401→  }> {
   402→    const primaryBaseSymbol = primaryCurrencyCode.split('_')[0];
   403→    const primaryRate = new Decimal(
   404→      await this.currencyRatesService.rateInUSD(primaryBaseSymbol),
   405→    );
   406→    const totalNeededUSD = totalDeductionInPrimary.div(primaryRate);
   407→
   408→    const otherBalances = await this.balanceService.getOtherBalancesForUpdate(
   409→      tenantAccountId,
   410→      primaryBalanceId,
   411→      trx,
   412→    );
   413→
   414→    const uplift = new Decimal(CROSS_CURRENCY_COMMISSION_UPLIFT);
   415→
   416→    for (const otherBalance of otherBalances) {
   417→      const otherBaseSymbol = otherBalance.currencyCode.split('_')[0];
   418→      const otherRate = new Decimal(
   419→        await this.currencyRatesService.rateInUSD(otherBaseSymbol),
   420→      );
   421→
   422→      const neededInOther = totalNeededUSD.mul(otherRate);
   423→      const baseComm = new Decimal(
   424→        new Commission(
   425→          neededInOther.toString(),
   426→          otherBalance.withdrawalCommission,
   427→        ).only(),
   428→      );
   429→      const upliftedComm = baseComm.mul(uplift.plus(1));
   430→      const totalNeeded = neededInOther.plus(upliftedComm);
   431→      const available = new Decimal(otherBalance.visualBalance);
   432→
   433→      if (totalNeeded.gt(available)) continue;
   434→
   435→      await this.balanceService.decreaseBalance(
   436→        otherBalance.id,
   437→        totalNeeded.toFixed(otherBalance.decimalPlaces),
   438→        otherBalance.decimalPlaces,
   439→        trx,
   440→        {
   441→          operation: BalanceOperationType.CROSS_CURRENCY_WITHDRAWAL,
   442→          relatedEntityId: withdrawalId,
   443→          relatedEntityName: 'WithdrawalEntity',
   444→          operationMeta: {
   445→            sourceCurrencyCode: otherBalance.currencyCode,
   446→            exchangeRateToUSD: otherRate.toString(),
   447→            withdrawalCommission: otherBalance.withdrawalCommission,
   448→          },
   449→        },
   450→      );
   451→
   452→      const commissionUSD = upliftedComm.div(otherRate);
   453→      return {
   454→        usedCurrencyCode: otherBalance.currencyCode,
   455→        commissionAmount: parseFloat(
   456→          upliftedComm.toDecimalPlaces(otherBalance.decimalPlaces).toString(),
   457→        ),
   458→        commissionAmountUsd: parseFloat(
   459→          commissionUSD.toDecimalPlaces(2).toString(),
   460→        ),
   461→      };
   462→    }
   463→
   464→    throw ExceptionFactory.create({
   465→      exceptionCode: 'withdrawal.insufficientBalance',
   466→      statusCode: HttpStatus.BAD_REQUEST,
   467→      message:
   468→        'Insufficient balance: no single currency can cover the full withdrawal',
   469→    });
   470→  }
