     1→import { HttpStatus, Inject, Injectable } from '@nestjs/common';
     2→import { ConfigType } from '@nestjs/config';
     3→import * as bitcoin from 'bitcoinjs-lib';
     4→import ECPairFactory from 'ecpair';
     5→import * as ecc from 'tiny-secp256k1';
     6→import Decimal from 'decimal.js';
