     8→import { ExceptionFactory } from '@shared/exceptions';
     9→import { INetworkAccount } from '../../types/network-account.type';
    10→import {
    11→  IGetTransactionHistoryParams,
    12→  INetworkTransaction,
    13→  SupportedNetworks,
    14→} from '../../types/network.type';
    15→import { INetworkService, ISweepBaseParams } from '../../types/network-service';
    16→import { MempoolService } from './mempool.service';
    17→import {
    18→  BTC_DEFAULT_FEE_RATE_SAT_PER_VBYTE,
    19→  BTC_SATOSHI_PER_BTC,
    20→} from '../constant';
    21→
    22→const ECPair = ECPairFactory(ecc);
    23→
    24→@Injectable()
    25→export class BtcNetworkService implements INetworkService {
    26→  readonly networkName = SupportedNetworks.BTC;
    27→
    28→  private readonly btcNetwork: bitcoin.Network;
    29→
    30→  constructor(
    31→    private readonly mempoolService: MempoolService,
    32→    @Inject(networksConfigs.KEY)
    33→    private readonly networksConf: ConfigType<typeof networksConfigs>,
    34→  ) {
    35→    this.btcNetwork =
    36→      networksConf.btc.network === 'mainnet'
    37→        ? bitcoin.networks.bitcoin
    38→        : bitcoin.networks.testnet;
    39→  }
    40→
    41→  async createAccount(): Promise<INetworkAccount> {
    42→    const keyPair = ECPair.makeRandom({ network: this.btcNetwork });
    43→    const { address } = bitcoin.payments.p2wpkh({
    44→      pubkey: Buffer.from(keyPair.publicKey),
    45→      network: this.btcNetwork,
    46→    });
    47→
    48→    if (!address) {
    49→      throw new Error('Failed to derive BTC address');
    50→    }
    51→
    52→    return {
    53→      address,
    54→      privateKey: keyPair.toWIF(),
    55→      publicKey: Buffer.from(keyPair.publicKey).toString('hex'),
    56→      meta: {},
    57→    };
    58→  }
    59→
    60→  async sweepBase(
    61→    params: ISweepBaseParams,
    62→  ): Promise<{ transactionHash: string; amount: string }> {
    63→    const { fromAddress, fromPrivateKey, toAddress, amount } = params;
    64→
    65→    const utxos = await this.mempoolService.getUtxos(fromAddress);
    66→    const confirmedUtxos = utxos.filter((u) => u.status.confirmed);
    67→
    68→    if (confirmedUtxos.length === 0) {
    69→      throw ExceptionFactory.create({
    70→        exceptionCode: 'network.btcNoConfirmedUtxos',
    71→        statusCode: HttpStatus.BAD_REQUEST,
    72→        message: 'No confirmed UTXOs available for sweep',
    73→      });
    74→    }
    75→
    76→    const totalSats = confirmedUtxos.reduce((sum, u) => sum + u.value, 0);
    77→
    78→    let feeRateSatPerVbyte: number;
    79→    try {
    80→      const fees = await this.mempoolService.getRecommendedFees();
    81→      feeRateSatPerVbyte = fees.hourFee;
    82→    } catch {
    83→      feeRateSatPerVbyte = BTC_DEFAULT_FEE_RATE_SAT_PER_VBYTE;
    84→    }
    85→
    86→    const numInputs = confirmedUtxos.length;
    87→    const DUST_LIMIT = 546n;
    88→
    89→    let sendSats: bigint;
    90→    let changeSats = 0n;
    91→
    92→    if (amount) {
    93→      const estimatedVBytes = 10 + 68 * numInputs + 31 * 2;
    94→      const feeSats = BigInt(estimatedVBytes * feeRateSatPerVbyte);
    95→      const requestedSats = BigInt(
    96→        new Decimal(amount)
    97→          .mul(BTC_SATOSHI_PER_BTC)
    98→          .toDecimalPlaces(0)
    99→          .toString(),
   100→      );
   101→      const available = BigInt(totalSats) - feeSats;
   102→      if (requestedSats >= available) {
   103→        sendSats = available;
   104→      } else {
   105→        sendSats = requestedSats;
   106→        changeSats = available - requestedSats;
   107→        if (changeSats <= DUST_LIMIT) {
   108→          changeSats = 0n;
   109→        }
   110→      }
   111→    } else {
   112→      const estimatedVBytes = 10 + 68 * numInputs + 31 * 1;
   113→      const feeSats = BigInt(estimatedVBytes * feeRateSatPerVbyte);
   114→      sendSats = BigInt(totalSats) - feeSats;
   115→    }
   116→
   117→    if (sendSats <= 0n) {
   118→      throw ExceptionFactory.create({
   119→        exceptionCode: 'network.btcInsufficientFunds',
   120→        statusCode: HttpStatus.BAD_REQUEST,
   121→        message: 'Insufficient BTC balance to cover transaction fee',
   122→      });
   123→    }
   124→
   125→    const keyPair = ECPair.fromWIF(fromPrivateKey, this.btcNetwork);
   126→    const psbt = new bitcoin.Psbt({ network: this.btcNetwork });
   127→
   128→    for (const utxo of confirmedUtxos) {
   129→      psbt.addInput({
   130→        hash: utxo.txid,
   131→        index: utxo.vout,
   132→        witnessUtxo: {
   133→          script: bitcoin.payments.p2wpkh({
   134→            pubkey: Buffer.from(keyPair.publicKey),
   135→            network: this.btcNetwork,
   136→          }).output!,
   137→          value: BigInt(utxo.value),
   138→        },
   139→      });
   140→    }
   141→
   142→    psbt.addOutput({
   143→      address: toAddress,
   144→      value: sendSats,
   145→    });
   146→
   147→    if (changeSats > 0n) {
   148→      psbt.addOutput({
   149→        address: fromAddress,
   150→        value: changeSats,
   151→      });
   152→    }
   153→
   154→    for (let i = 0; i < confirmedUtxos.length; i++) {
   155→      psbt.signInput(i, keyPair);
   156→    }
   157→
   158→    psbt.finalizeAllInputs();
   159→    const txHex = psbt.extractTransaction().toHex();
   160→    const txid = await this.mempoolService.broadcastTx(txHex);
   161→
   162→    const sentBtc = new Decimal(sendSats.toString()).div(BTC_SATOSHI_PER_BTC);
   163→
   164→    return {
   165→      transactionHash: txid.trim(),
   166→      amount: sentBtc.toString(),
   167→    };
   168→  }
