   170→  async sweepToken(
   171→    _oneTimeWalletPrivateKey: string,
   172→    _currencyCode: string,
   173→    _destinationAddress: string,
   174→    _amount?: string,
   175→  ): Promise<{ transactionHash: string; amount: string }> {
   176→    throw ExceptionFactory.create({
   177→      exceptionCode: 'network.btcTokensNotSupported',
   178→      statusCode: HttpStatus.BAD_REQUEST,
   179→      message: 'Bitcoin does not support token transfers',
   180→    });
   181→  }
