   183→  async verifyTransaction(transactionHash: string): Promise<boolean> {
   184→    const tx = await this.mempoolService.getTx(transactionHash);
   185→    return tx?.status?.confirmed === true;
   186→  }
   187→
   188→  async getBalance(address: string): Promise<string> {
   189→    const info = await this.mempoolService.getAddressInfo(address);
   190→    const sats =
   191→      info.chain_stats.funded_txo_sum - info.chain_stats.spent_txo_sum;
   192→    return new Decimal(sats).div(BTC_SATOSHI_PER_BTC).toString();
   193→  }
   194→
   195→  async getTransactionHistory(
   196→    options: IGetTransactionHistoryParams,
   197→  ): Promise<INetworkTransaction[]> {
   198→    const { address, sinceTimestamp, onlyConfirmed, onlyTo } = options;
   199→
   200→    const txs = await this.mempoolService.getAddressTxs(address);
   201→
   202→    const result: INetworkTransaction[] = [];
   203→
   204→    for (const tx of txs) {
   205→      if (onlyConfirmed && !tx.status.confirmed) {
   206→        continue;
   207→      }
   208→
   209→      if (
   210→        sinceTimestamp !== undefined &&
   211→        tx.status.block_time !== undefined &&
   212→        tx.status.block_time * 1000 < sinceTimestamp
   213→      ) {
   214→        continue;
   215→      }
   216→
   217→      const relevantOutputs = tx.vout.filter(
   218→        (out) => out.scriptpubkey_address === address,
   219→      );
   220→
   221→      if (onlyTo && relevantOutputs.length === 0) {
   222→        continue;
   223→      }
   224→
   225→      const fromAddress = tx.vin[0]?.prevout?.scriptpubkey_address ?? 'unknown';
   226→
   227→      for (const output of relevantOutputs) {
   228→        result.push({
   229→          transactionHash: tx.txid,
   230→          amount: new Decimal(output.value).div(BTC_SATOSHI_PER_BTC).toString(),
   231→          timestamp: (tx.status.block_time ?? 0) * 1000,
   232→          from: fromAddress,
   233→          to: address,
   234→        });
   235→      }
   236→
   237→      if (!onlyTo && relevantOutputs.length === 0) {
   238→        result.push({
   239→          transactionHash: tx.txid,
   240→          amount: '0',
   241→          timestamp: (tx.status.block_time ?? 0) * 1000,
   242→          from: fromAddress,
   243→          to: address,
   244→        });
   245→      }
   246→    }
   247→
   248→    return result;
   249→  }
   250→}
